import { redirect } from "next/navigation";
import { headers } from "next/headers";
import { AppShell } from "@ui/layouts/AppShell/AppShell";
import { mockCompanies, createAccountLabel } from "@core/navigation/sidebar.config";
import { resolveActiveModules } from "@core/navigation/moduleResolver";
import { hasModules } from "@core/navigation/hasModules";
import { ToastProvider } from "@core/toast/ToastProvider";
import { ToastStack } from "@ui/containers/ToastStack/ToastStack";
import { ModuleGuard } from "@ui/containers/ModuleGuard/ModuleGuard";

import { productConfig } from "@/product.config";
import { modulesRegistry } from "@/modules.registry";

export default async function ShellLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const headersList = await headers();
    const pathname = headersList.get("x-pathname") || "";

    // 1. Resolvemos dinámicamente los módulos activos según configuración del producto
    const items = resolveActiveModules({
        config: productConfig,
        registry: modulesRegistry
    });

    // 2. Determinamos si hay módulos activados para la lógica de visualización
    const modulesActive = hasModules(items);
    
    // 3. Metadata del sistema
    const appName = "Control";

    return (
        <ToastProvider>
            <AppShell
                sidebarItems={items}
                appName={appName}
                companies={mockCompanies}
                createLabel={createAccountLabel}
                hideSelector={!modulesActive}
            >
                <ModuleGuard 
                    currentPath={pathname} 
                    activeModules={modulesRegistry.filter(m => productConfig.enabledModules.includes(m.id))}
                >
                    {children}
                </ModuleGuard>
            </AppShell>
            <ToastStack />
        </ToastProvider>
    );
}
