import { SidebarGroup } from "@ui/layouts/Sidebar/Sidebar.types";

export interface ModuleRegistryItem {
  id: string;
  label: string;
  routeBase: string;
  navGroup: string;
  icon: string;
  children?: { label: string; href: string }[];
}

export interface ProductConfig {
  productId: string;
  enabledModules: string[];
  navOrder: string[];
  navGroups?: string[];
}

/**
 * resolveActiveModules
 * Único punto de verdad para transformar la configuración del producto
 * y el registro de módulos en la estructura necesaria para el Sidebar.
 */
export function resolveActiveModules({
  config,
  registry
}: {
  config: ProductConfig;
  registry: ModuleRegistryItem[];
}): SidebarGroup[] {
  // 1. Filtrar solo los módulos habilitados para este producto
  const activeModules = registry.filter((m) => config.enabledModules.includes(m.id));

  // 2. Ordenar según navOrder de la config
  const sortedModules = [...activeModules].sort((a, b) => {
    const indexA = config.navOrder.indexOf(a.id);
    const indexB = config.navOrder.indexOf(b.id);
    // Si no está en navOrder, lo mandamos al final
    const finalIndexA = indexA === -1 ? 999 : indexA;
    const finalIndexB = indexB === -1 ? 999 : indexB;
    return finalIndexA - finalIndexB;
  });

  // 3. Agrupar módulos
  const groupsMap: Record<string, SidebarGroup> = {};
  
  // Pre-inicializar grupos si vienen en config para mantener el orden de grupos
  const groupOrder = config.navGroups || [];
  groupOrder.forEach(name => {
    groupsMap[name] = { title: name, items: [] };
  });

  sortedModules.forEach((m) => {
    const groupName = m.navGroup || "General";
    if (!groupsMap[groupName]) {
      groupsMap[groupName] = { title: groupName, items: [] };
    }

    groupsMap[groupName].items.push({
      label: m.label,
      href: m.routeBase,
      icon: m.icon,
      expandable: !!(m.children && m.children.length > 0),
      children: m.children?.map((c) => ({
        label: c.label,
        href: c.href
      }))
    });
  });

  // 4. Retornar en el orden de grupos especificado o por defecto
  if (groupOrder.length > 0) {
    return groupOrder
      .map(name => groupsMap[name])
      .filter(g => g && g.items.length > 0);
  }

  return Object.values(groupsMap).filter((g) => g.items.length > 0);
}
